import{_ as a,o as i,c as s,ae as t}from"./chunks/framework.DNl3Z2rO.js";const g=JSON.parse('{"title":"Git 规范","description":"","frontmatter":{"title":"Git 规范"},"headers":[],"relativePath":"engineering/git.md","filePath":"engineering/git.md"}'),r={name:"engineering/git.md"};function l(n,e,o,d,h,c){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="git-规范" tabindex="-1">Git 规范 <a class="header-anchor" href="#git-规范" aria-label="Permalink to &quot;Git 规范&quot;">​</a></h1><h2 id="_1-git-提交日志格式规范" tabindex="-1">1. Git 提交日志格式规范 <a class="header-anchor" href="#_1-git-提交日志格式规范" aria-label="Permalink to &quot;1. Git 提交日志格式规范&quot;">​</a></h2><h3 id="_1-1-前言" tabindex="-1">1.1. 前言 <a class="header-anchor" href="#_1-1-前言" aria-label="Permalink to &quot;1.1. 前言&quot;">​</a></h3><p>为什么要对 <code>Git</code> 提交日志（<code>message</code>）的格式进行规范约束？</p><ol><li>更方便、快捷地浏览和了解项目的历史信息。</li><li>有利于保证提交内容的独立性，避免把所有改动都放在一个提交里面。</li><li>便于通过脚本自动化生成 <code>CHANGELOG</code>。</li></ol><h3 id="_1-2-基本的-message-格式" tabindex="-1">1.2. 基本的 <code>message</code> 格式 <a class="header-anchor" href="#_1-2-基本的-message-格式" aria-label="Permalink to &quot;1.2. 基本的 \`message\` 格式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;type&gt;[optional scope]: &lt;subject&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[optional body]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[optional footer(s)]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>其中 <code>message header</code>（即首行）必选，scope、body 和 footer 可选。</p><h4 id="_1-2-1-字数限制" tabindex="-1">1.2.1. 字数限制 <a class="header-anchor" href="#_1-2-1-字数限制" aria-label="Permalink to &quot;1.2.1. 字数限制&quot;">​</a></h4><ul><li>header（首行）：只有一行，不超过 50 个字符</li><li>body：每行不超过 72 个字符</li><li>footer：每行不超过 72 个字符</li></ul><h4 id="_1-2-2-语言选择" tabindex="-1">1.2.2. 语言选择 <a class="header-anchor" href="#_1-2-2-语言选择" aria-label="Permalink to &quot;1.2.2. 语言选择&quot;">​</a></h4><p><strong>在开源项目中</strong>：推荐使用英文，因为项目的开发者和参与者可能来自世界各地，使用英文可以更广泛的传递信息。</p><p><strong>在内部项目（并且短时间内也不涉及开源）中</strong>：应该选择内部人员普遍能够熟练表达的语言。</p><h3 id="_1-3-message-header" tabindex="-1">1.3. message header <a class="header-anchor" href="#_1-3-message-header" aria-label="Permalink to &quot;1.3. message header&quot;">​</a></h3><h4 id="_1-3-1-type" tabindex="-1">1.3.1. type <a class="header-anchor" href="#_1-3-1-type" aria-label="Permalink to &quot;1.3.1. type&quot;">​</a></h4><p><code>type</code> 用来描述本次提交的改动类型，可选值及对应含义如下：</p><ul><li><code>feat</code>: 新增功能</li><li><code>fix</code>: 修复 bug</li><li><code>docs</code>: 文档相关的改动</li><li><code>style</code>: 对代码的格式化改动，代码逻辑并未产生任何变化(例如代码缩进，分号的移除和添加)</li><li><code>test</code>: 新增或修改测试用例</li><li><code>refactor</code>: 重构代码或其他优化举措</li><li><code>chore</code>: 项目工程方面的改动，代码逻辑并未产生任何变化</li><li><code>revert</code>: 恢复之前的提交</li></ul><h4 id="_1-3-2-scope" tabindex="-1">1.3.2. scope <a class="header-anchor" href="#_1-3-2-scope" aria-label="Permalink to &quot;1.3.2. scope&quot;">​</a></h4><p><code>scope</code> 用来描述本次提交所涉及到的改动范围（例如模块、功能或其他任何限定的范围）。</p><h4 id="_1-3-3-subject" tabindex="-1">1.3.3. subject <a class="header-anchor" href="#_1-3-3-subject" aria-label="Permalink to &quot;1.3.3. subject&quot;">​</a></h4><p>subject 用来概括和描述本次提交的改动内容，需注意以下几点：</p><ol><li>时态方面使用一般现在时，不要使用过去时。</li><li>句式使用祈使句。即一般情况不要增加主语。</li><li>句首无需大写，句尾无需结束标点。</li></ol><h3 id="_1-4-message-body" tabindex="-1">1.4. message body <a class="header-anchor" href="#_1-4-message-body" aria-label="Permalink to &quot;1.4. message body&quot;">​</a></h3><p>日志的内容主体 body 用来描述详细的提交内容，可写可不写，需注意以下几点：</p><ol><li>时态方面使用一般现在时，不要用过去时态。</li><li>句式视情况而定，一般使用祈使句式。</li><li>标点方面遵循一般的文档格式规范。</li></ol><h3 id="_1-5-message-footer" tabindex="-1">1.5. message footer <a class="header-anchor" href="#_1-5-message-footer" aria-label="Permalink to &quot;1.5. message footer&quot;">​</a></h3><p>footer 通常用于代码评审过程记录、作者签名等。例如：</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Reported-by: User1 &lt;</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">user1@example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Helped-by: User2 &lt;</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">user2@example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Reviewed-by: User3 &lt;</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">user3@example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Signed-off-by: Author &lt;</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">author@example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h4 id="引用-issues" tabindex="-1">引用 <code>Issues</code> <a class="header-anchor" href="#引用-issues" aria-label="Permalink to &quot;引用 \`Issues\`&quot;">​</a></h4><p>可以在 <code>commit</code> 信息里使用关键字 + <code>Issue ID</code> 来表明该提交解决了某个 <code>Issue</code>。推荐使用的关键字有：</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">close closes closed fix fixes fixed resolve resolves resolved</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="破坏性变动-breaking-changes" tabindex="-1">破坏性变动（<code>Breaking changes</code>） <a class="header-anchor" href="#破坏性变动-breaking-changes" aria-label="Permalink to &quot;破坏性变动（\`Breaking changes\`）&quot;">​</a></h4><p>如果本次提交的改动是破坏性的，需要在这里声明。</p><h2 id="_2-git-分支命名规范" tabindex="-1">2. Git 分支命名规范 <a class="header-anchor" href="#_2-git-分支命名规范" aria-label="Permalink to &quot;2. Git 分支命名规范&quot;">​</a></h2><h3 id="_2-1-分支模型选择的说明" tabindex="-1">2.1. 分支模型选择的说明 <a class="header-anchor" href="#_2-1-分支模型选择的说明" aria-label="Permalink to &quot;2.1. 分支模型选择的说明&quot;">​</a></h3><p>目前互联网和社区中流传最广泛的一个分支模型 <a href="https://github.com/nvie/gitflow" target="_blank" rel="noreferrer">Git Flow</a> 出自 <a href="https://nvie.com/posts/a-successful-git-branching-model/" target="_blank" rel="noreferrer">a-successful-git-branching-model</a> 这篇十年前的文章，文章作者 Vincent Driessen 在 2020 年三月份的时候已经公开表示，该分支模型已经不适用于现如今持续交付的软件工程方式，推荐在持续交付的软件工程中使用更简单的 <a href="https://guides.github.com/introduction/flow/" target="_blank" rel="noreferrer">Github Flow</a> 模型。</p><h3 id="_2-2-分支命名" tabindex="-1">2.2. 分支命名 <a class="header-anchor" href="#_2-2-分支命名" aria-label="Permalink to &quot;2.2. 分支命名&quot;">​</a></h3><p>新建分支的命名格式为：<code>{type}-{issue id}-the-thing-you-do</code></p><ul><li><code>type</code>：和上文 1.3.1 章节中的 type 保持一致</li><li><code>issue id</code>：与分支内容相关的 issue id，如果无关，则可以忽略</li></ul><h3 id="_2-3-多版本分支命名" tabindex="-1">2.3. 多版本分支命名 <a class="header-anchor" href="#_2-3-多版本分支命名" aria-label="Permalink to &quot;2.3. 多版本分支命名&quot;">​</a></h3><p>在需要同时维护多个版本的项目中，可以每发布一个新的版本就单独拉一个新的分支，例如：</p><blockquote><ul><li><code>1.0.0-stable</code></li><li><code>2.0.0-stable</code></li></ul></blockquote><h2 id="_3-git-tag-命名规范" tabindex="-1">3. Git tag 命名规范 <a class="header-anchor" href="#_3-git-tag-命名规范" aria-label="Permalink to &quot;3. Git tag 命名规范&quot;">​</a></h2><p><code>Git tag</code> 就是通过语义化的名称来给仓库标注一个个具体的节点。</p><p>命名格式为 <code>v{semver}</code>，<code>semver</code> 是遵循 <a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">semantic version</a> 的版本号，例如 <code>v1.2.3</code>。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li><a href="https://github.com/angular/angular.js/blob/master/CONTRIBUTING.md" target="_blank" rel="noreferrer">AngularJS 代码贡献指南</a></li><li><a href="https://docs.google.com/document/d/1QrDFcIiPjSLDn3EL15IJygNPiHORgU1_OOAqWjiDU5Y/edit#heading=h.j8e4paqkfz0q" target="_blank" rel="noreferrer">AngularJS Git Commit Message Conventions</a></li><li><a href="http://karma-runner.github.io/0.13/dev/git-commit-msg.html" target="_blank" rel="noreferrer">Karma 的 Git 日志规范</a></li><li><a href="http://stackoverflow.com/questions/3580013/should-i-use-past-or-present-tense-in-git-commit-messages" target="_blank" rel="noreferrer">StackOverflow - 在 Git 日志中我该用过去时态还是现在时态？</a></li><li><a href="https://nvie.com/posts/a-successful-git-branching-model/" target="_blank" rel="noreferrer">一个成功的 Git 分支模型</a></li><li><a href="https://git-scm.com/book/zh/v2/Git-%E5%9F%BA%E7%A1%80-%E6%89%93%E6%A0%87%E7%AD%BE" target="_blank" rel="noreferrer">Git 基础打标签</a></li><li><a href="https://en.wikipedia.org/wiki/Characters_per_line" target="_blank" rel="noreferrer">每行字符数</a></li><li><a href="https://www.conventionalcommits.org" target="_blank" rel="noreferrer">Conventional Commits</a></li></ol>`,47)])])}const u=a(r,[["render",l]]);export{g as __pageData,u as default};
